var now = new Date();
var start = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0);
var end = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 23, 59, 59);
return { timeMin: start.toISOString(), timeMax: end.toISOString(), today: now.toISOString().split('T')[0] };

function fb(a, b) { if (a) { return a; } return b; }
var events = fb(fb($.steps.listEvents.response, {}).items, []);
var transcripts = [];
var transcriptResp = fb($.steps.listTranscripts, {});
if (transcriptResp.response) {
  transcripts = fb(transcriptResp.response.files, []);
}
var today = $.steps.getDateBounds.output.today;

var meetingData = 'TODAY\'S MEETINGS (' + today + '):\n\n';
events.forEach(function(e, i) {
  var time = e.start ? (fb(fb(e.start.dateTime, e.start.date), '')) : '';
  meetingData += (i + 1) + '. ' + (fb(e.summary, '(no title)')) + '\n';
  meetingData += '   Time: ' + time + '\n';
  var attendees = (fb(e.attendees, [])).map(function(a) { return a.email; }).filter(Boolean);
  if (attendees.length > 0) meetingData += '   Attendees: ' + attendees.slice(0, 8).join(', ') + '\n';
  if (e.description) meetingData += '   Description: ' + e.description.slice(0, 200) + '\n';
  meetingData += '\n';
});

var transcriptData = '';
if (transcripts.length > 0) {
  transcriptData = 'RECENT TRANSCRIPTS:\n\n';
  transcripts.forEach(function(t, i) {
    transcriptData += (i + 1) + '. ' + t.name + ' (modified: ' + (fb(t.modifiedTime, '')) + ')\n';
    transcriptData += '   Link: ' + (fb(t.webViewLink, '')) + '\n\n';
  });
}

return { meetingData: meetingData, transcriptData: transcriptData, eventCount: events.length, transcriptCount: transcripts.length, today: today };

var data = $.steps.compileMeetingData.output;

var prompt = 'You are an executive assistant who specializes in extracting action items from meetings. Based on the calendar events and transcript information below, identify all action items, next steps, and follow-ups.\n\n';
prompt += data.meetingData + '\n';
if (data.transcriptData) prompt += data.transcriptData + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Extract specific, actionable next steps for each meeting\n';
prompt += '- Assign owners where possible based on attendee context\n';
prompt += '- Set priority levels (high, medium, low)\n';
prompt += '- Suggest deadlines based on meeting context\n';
prompt += '- Group related action items together\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "summary": "overview of today\'s meetings and key outcomes",\n';
prompt += '  "meetings": [\n';
prompt += '    {\n';
prompt += '      "title": "meeting name",\n';
prompt += '      "time": "meeting time",\n';
prompt += '      "actionItems": [\n';
prompt += '        { "action": "what to do", "owner": "who should do it", "priority": "high/medium/low", "deadline": "suggested deadline" }\n';
prompt += '      ],\n';
prompt += '      "keyDecisions": ["decision 1"],\n';
prompt += '      "followUpNeeded": true\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "topPriorities": ["top priority item 1", "top priority item 2"],\n';
prompt += '  "totalActionItems": 0\n';
prompt += '}';

return { prompt: prompt };

function fb(a, b) { if (a) { return a; } return b; }
var raw = fb($.steps.aiAnalysis.output, '');
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, meetings: [], totalActionItems: 0 }; }

function fb(a, b) { if (a) { return a; } return b; }
var ai = $.steps.parseResponse.output;
var today = $.steps.compileMeetingData.output.today;

var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':white_check_mark: Meeting Next Steps — ' + today, emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: fb(ai.summary, 'Action items extracted from today\'s meetings.') } });

var topPriorities = fb(ai.topPriorities, []);
if (topPriorities.length > 0) {
  var priText = '*:rotating_light: Top Priorities*\n';
  topPriorities.forEach(function(p, i) { priText += (i + 1) + '. ' + p + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: priText } });
}

blocks.push({ type: 'divider' });

var meetings = fb(ai.meetings, []);
meetings.forEach(function(m) {
  var mText = '*' + (fb(m.title, 'Meeting')) + '*';
  if (m.time) mText += ' at ' + m.time;
  mText += '\n';

  var items = fb(m.actionItems, []);
  items.forEach(function(item) {
    var priorityIcon = ':red_circle:';
    if (item.priority === 'medium') priorityIcon = ':large_orange_circle:';
    if (item.priority === 'low') priorityIcon = ':white_circle:';
    mText += priorityIcon + ' ' + item.action;
    if (item.owner) mText += ' — _' + item.owner + '_';
    if (item.deadline) mText += ' (by ' + item.deadline + ')';
    mText += '\n';
  });

  var decisions = fb(m.keyDecisions, []);
  if (decisions.length > 0) {
    mText += '\n*Decisions:*\n';
    decisions.forEach(function(d) { mText += '  > ' + d + '\n'; });
  }

  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: mText } });
  blocks.push({ type: 'divider' });
});

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':memo: ' + (fb(ai.totalActionItems, 0)) + ' action items extracted | Powered by Claude AI + One CLI' }] });

var fallback = 'Meeting Next Steps — ' + today + ': ' + (fb(ai.totalActionItems, 0)) + ' action items';
return { blocks: blocks, fallback: fallback };
